48	// Helper type to make it cleaner to write visitor for std::variant.
49	template <class... Ts>
50	struct overloaded : Ts... {
51	  using Ts::operator()...;
52	};
53	// explicit deduction guide (not needed as of C++20)
54	template <class... Ts>
55	overloaded(Ts...) -> overloaded<Ts...>;
