188	void emitSummary(StringRef summary, raw_ostream &os) {
189	  if (!summary.empty()) {
190	    StringRef trimmed = summary.trim();
191	    char first = std::toupper(trimmed.front());
192	    StringRef rest = trimmed.drop_front();
193	    os << "\n_" << first << rest << "_\n\n";
194	  }
195	}
