207	std::vector<std::string> covertSyntaxToSignature(const Operator &op) {
208	  std::vector<std::string> signature;
209	
210	  std::string opName = op.getOperationName();
211	  StringRef format = op.getAssemblyFormat().trim();
212	
213	  // Split the string by spaces.
214	  SmallVector<StringRef, 8> split;
215	  format.split(split, ' ');
216	
217	  for (auto &parameter : split) {
218	    if (parameter.trim(" \n") == "`:`") {
219	      break;
220	    } else if (parameter.trim(" \n") == "attr-dict") {
221	      continue;
222	    }
223	    signature.push_back(parameter.trim("`").str());
224	  }
225	
226	  return signature;
227	}
