249	        emitter.os << " and ";
250	      } else {
251	        emitter.os << ", ";
252	      }
253	    }
254	    emitter.os << Code{name};
255	    i++;
256	  }
257	  emitter.os << " must have the same element type (" << TileIRTy{arg.type}
258	             << ").\n";
