374	static void emitEnumAttribute(SpecEmitter &emitter,
375	                              const TileIREnumAttr &enumAttr) {
376	  emitter.emitAnchor(enumAttr.getAnchor());
377	
378	  emitter.emitDescription(enumAttr.prefixDescription);
379	
380	  std::vector<std::string> disabledVariants;
381	  for (const auto &enumcase : enumAttr.enumcases) {
382	    if (!enumcase.isSelected) {
383	      disabledVariants.push_back(Code{enumcase.str});
384	      continue;
385	    }
386	
387	    emitter.os << "- " << Code{enumcase.str} << " - " << enumcase.description
388	               << "\n";
389	  }
390	
391	  emitter.os << "\n\n";
392	
393	  if (!disabledVariants.empty()) {
394	    emitter.os
395	        << "Note: The following variants are not supported by this operation: "
396	        << llvm::join(disabledVariants, ", ") << ".\n";
397	  }
398	
399	  emitter.os << "\n\n";
400	  emitter.emitDescription(enumAttr.suffixDescription);
401	}
402	
403	static void emitAttributeDef(SpecEmitter &emitter,
404	                             const TileIRAttrDef &attrDef) {
405	  emitter.emitAnchor(attrDef.getAnchor());
406	  std::cout << "prefixDescription: " << attrDef.prefixDescription << "\n";
407	  emitter.emitDescription(attrDef.prefixDescription);
408	  int i = 0;
409	  for (auto &exampleText : attrDef.examples) {
410	    auto processedExample = processExample(exampleText);
411	    auto exampleName =
412	        attrDef.opName + "_example_" + attrDef.name + "_" + std::to_string(i);
413	    emitter.emitExample(exampleName, processedExample);
414	    i++;
415	  }
416	  emitter.os << "\n\n";
417	}
