419	static void
420	emitAttributeInterface(SpecEmitter &emitter,
421	                       const TileIRAttrInterface &attrInterface,
422	                       const std::vector<const Record *> &attrDefs) {
423	  std::cout << "emitAttributeInterface: " << attrInterface.name << std::endl;
424	  emitter.emitAnchor(attrInterface.getAnchor());
425	  emitter.emitDescription(attrInterface.prefixDescription);
426	
427	  auto implementators = findInterfaceImplementors(attrInterface, attrDefs);
428	
429	  emitter.os << Header(OP_DETAILS_HEADER_LEVEL,
430	                       attrInterface.name + " Implementers");
431	
432	  for (auto &attr : implementators) {
433	    emitter.os << Header(OP_DETAILS_HEADER_LEVEL, attr.name);
434	    emitAttributeDef(emitter, attr);
435	  }
436	
437	  emitter.emitDescription(attrInterface.suffixDescription);
438	}
