440	static void emitAttribute(SpecEmitter &emitter, const TileIRAttr &attr,
441	                          const std::vector<const Record *> &attrDefs) {
442	  std::visit(
443	      overloaded{
444	          [&](const TileIREnumAttr &arg) { emitEnumAttribute(emitter, arg); },
445	          [&](const TileIRAttrDef &arg) { emitAttributeDef(emitter, arg); },
446	          [&](const TileIRAttrInterface &arg) {
447	            emitAttributeInterface(emitter, arg, attrDefs);
448	          },
449	      },
450	      attr);
451	}
