538	static void emitOpDoc(SpecEmitter &emitter, CudaTileOp &cudaTileOp,
539	                      std::vector<const Record *> &attrDefs) {
540	  // We can create per-operation badges that we can attach when rendering it.
541	  std::vector<Badge> badges;
542	
543	  // TODO: get the operation version here, we need to pull OperationSignature
544	  // up.
545	  emitter.emitOpHeading(cudaTileOp.getOperationName());
546	
547	  // TODO: This should probably be folded into an emitter method or
548	  // emitOpHeading.
549	  bool first = true;
550	  for (const auto &badge : badges) {
551	    if (first) {
552	      emitter.os << badge;
553	    } else {
554	      emitter.os << " " << badge;
555	    }
556	  }
557	
558	  if (!badges.empty()) {
559	    emitter.os << "\n\n";
560	  }
561	
562	  // Emit the summary, syntax, and description if present.
563	  if (cudaTileOp.op.hasSummary())
564	    emitter.emitSummary(cudaTileOp.op.getSummary());
565	
566	  emitOperationSignature(emitter, cudaTileOp);
567	
568	  emitter.os << Header(OP_DETAILS_HEADER_LEVEL, "Description");
569	  if (cudaTileOp.op.hasDescription())
570	    // todo delete this helper and move to emitter.h
571	    emitter.emitDescription(cudaTileOp.getDescription());
572	
573	  // Emit the attributes.
574	  auto attributes = cudaTileOp.getAttributes();
575	  for (const auto &enumAttr : attributes) {
576	    emitAttribute(emitter, enumAttr, attrDefs);
577	  }
578	
579	  // Emit the description tables.
580	  auto descriptionTables = cudaTileOp.getDescriptionTables();
581	  int i = 0;
582	  for (auto &table : descriptionTables) {
583	    auto anchor =
584	        "table-" + cudaTileOp.getOperationName() + "-" + std::to_string(i);
585	    table.anchors.push_back(anchor);
586	    emitter.os << table;
587	    i++;
588	  }
589	
590	  emitter.os << "\n";
591	
592	  // Finally emit the constraints.
593	  emitter.os << Header(OP_DETAILS_HEADER_LEVEL, "Constraints");
594	  emitter.os << "\n";
595	  if (!cudaTileOp.signature.constraints.empty()) {
596	    for (auto &constraint : cudaTileOp.signature.constraints) {
597	      emitter.os << "- ";
598	      emitOperationConstraint(emitter, constraint);
599	      emitter.os << "\n";
600	    }
601	  } else {
602	    emitter.os << "No constraints."
603	               << "\n\n";
604	  }
605	
606	  emitter.os << "\n\n";
607	
608	  if (!cudaTileOp.getMLIRExamples().empty()) {
609	    emitter.os << Header(OP_DETAILS_HEADER_LEVEL, "Examples");
610	    int i = 0;
611	    for (auto &example : cudaTileOp.getMLIRExamples()) {
612	      std::string exampleName =
613	          cudaTileOp.getOperationName() + "_" + std::to_string(i);
614	      emitOperationExample(emitter, exampleName, example);
615	      i++;
616	    }
617	  }
618	
619	  // TODO: emit information about the regions.
620	
621	  // Emit successors.
622	  // if (op.getNumSuccessors() != 0) {
623	  //   os << Header(OP_DETAILS_HEADER_LEVEL, "Successors:");
624	  //   os << "| Successor | Description |\n"
625	  //      << "| :-------: | ----------- |\n";
626	  //   for (const auto &it : op.getSuccessors())
627	  //     emitNamedConstraint(it, os);
628	  // }
629	
630	  emitter.os << "\n";
631	}
632	
633	// These are the declared sections.
634	static const char *const cudaTileSections[] = {
635	    "Core",           "Conversions",   "Control Flow", "Memory",
636	    "Floating Point", "Integer",       "Bitwise",      "Atomics",
637	    "Views",          "Miscellaneous", "Testing",
638	};
639	
640	static const int NUMBER_SECTIONS =
641	    sizeof(cudaTileSections) / sizeof(cudaTileSections[0]);
642	
643	static std::vector<std::pair<std::string, std::vector<const Record *>>>
644	splitBySections(const RecordKeeper &records) {
645	  // First we sort by `cudaTileGroup` then we emit.
646	  std::unordered_map<std::string, std::vector<const Record *>> groupedOps;
647	
648	  auto opDefs = getRequestedOpDefinitions(records);
649	
650	  for (const Record *opDef : opDefs) {
651	    CudaTileOp op = CudaTileOp(opDef);
652	    auto cudaTileGroup = op.getCudaTileSpecGroup();
653	    if (groupedOps.count(cudaTileGroup) == 0) {
654	      groupedOps[cudaTileGroup] = {opDef};
655	    } else {
656	      groupedOps[cudaTileGroup].push_back(opDef);
657	    }
658	  }
659	
660	  std::unordered_map<std::string, int> cudaTileGroupLabels;
661	  for (int i = 0; i < NUMBER_SECTIONS; i++) {
662	    // std::cout << "LABEL";
663	    // std::cout << cudaTileSections[i] << " " << i + 1 << std::endl;
664	    cudaTileGroupLabels[cudaTileSections[i]] = i + 1;
665	  }
666	
667	  std::vector<std::pair<std::string, std::vector<const Record *>>>
668	      orderedSections(groupedOps.begin(), groupedOps.end());
669	
670	  std::sort(orderedSections.begin(), orderedSections.end(),
671	            [&](const std::pair<std::string, std::vector<const Record *>> &a,
672	                std::pair<std::string, std::vector<const Record *>> &b) {
673	              int aScore = -1;
674	              int bScore = -1;
675	
676	              if (cudaTileGroupLabels.count(a.first) > 0) {
677	                aScore = cudaTileGroupLabels[a.first];
678	              }
679	
680	              if (cudaTileGroupLabels.count(b.first) > 0) {
681	                bScore = cudaTileGroupLabels[b.first];
682	              }
683	
684	              return aScore < bScore;
685	            });
686	
687	  return orderedSections;
688	}
689	
690	void cudatile::tblgen::generateSpec(
691	    raw_ostream &os, const llvm::RecordKeeper &records,
692	    const std::optional<std::string> &examplesDirectory) {
693	  raw_indented_ostream raw_ios(os);
694	  SpecEmitter emitter(raw_ios, examplesDirectory);
695	
696	  // This should probably be moved to the emitter.
697	  emitter.emitComment(AUTO_GENERATED_MESSAGE);
698	
699	  // The spec generation today only considers the dialect ops and nothing else.
700	
701	  // Split the ops by sections.
702	  auto orderedSections = splitBySections(records);
703	
704	  std::vector<const Record *> attrDefs;
705	  for (const auto &def : records.getDefs()) {
706	    if (def.second->isSubClassOf("AttrDef")) {
707	      attrDefs.push_back(def.second.get());
708	    }
709	  }
710	
711	  for (auto const &pair : orderedSections) {
712	    // The first part of the pair is the section name/heading.
713	    auto cudaTileGroupLabel = pair.first;
714	    // The second is a lit of the records corresponding to the operations in the
715	    // section/group.
716	    auto groupOps = pair.second;
717	
718	    // Skip documenting any testing operations.
719	    if (cudaTileGroupLabel == "Testing") {
720	      continue;
721	    }
722	
723	    // An anchor declares a thing that can be references elsewhere in the
724	    // document.
725	    //
726	    // Generate an anchor of the form op-group-<cudaTileGroupLabel>.
727	    std::string normalizedGroupLabel(cudaTileGroupLabel);
728	    std::replace(normalizedGroupLabel.begin(), normalizedGroupLabel.end(), ' ',
729	                 '-');
730	    emitter.emitAnchor("op-group", normalizedGroupLabel);
731	
732	    // Emit a header for the section at the SECTION_HEADER_LEVEL.
733	    //
734	    // Generates:
735	    //
736	    // <cudaTileGroupLabel>
737	    // ====================
738	
739	    emitter.os << Header(SECTION_HEADER_LEVEL, cudaTileGroupLabel);
740	
741	    // Include the pre-written header text for the section.
742	    //
743	    // Generates:
744	    //
745	    // .. include:: /sections/op_class_headings/<cudaTileGroupLabel>_heading.rst
746	    //
747	    // The is the pre-written text for the section.
748	    //
749	    // TODO: modify to use emitInclude.
750	    emitter.os << ".. include:: " << OP_CLASS_HEADING_PATH << cudaTileGroupLabel
751	               << "_heading.rst"
752	               << "\n\n";
753	
754	    // Finally we iterate over each operation in the group and emit a section
755	    // for it.
756	    for (auto opDef : groupOps) {
757	      // Note: construct here due to ownership/lifetime issues with storing
758	      // the ops in vector.
759	      Operator op(opDef);
760	      CudaTileOp cudaTileOp(op);
761	      // Call emitOpDoc with the emitter and the operation.
762	      emitOpDoc(emitter, cudaTileOp, attrDefs);
763	    }
764	
765	  }
766	}
