std::string CudaTileOp::getCudaTileSpecGroup() {
  auto def = this->op.getDef();
  auto mdef = def.getValueAsOptionalDef("metadata");

  if (mdef != nullptr) {
    auto cudaTileGroup = mdef->getValueAsOptionalString("cudaTileSpecGroup");
    if (cudaTileGroup) {
      return cudaTileGroup->str();
    }
  }

  return "Miscellanous";
}

