  auto def = this->op.getDef();
  auto mdef = def.getValueAsOptionalDef("metadata");

  if (mdef != nullptr) {
    auto cudaTileSubGroup =
        mdef->getValueAsOptionalString("cudaTileSpecSubGroup");
    if (cudaTileSubGroup) {
      return cudaTileSubGroup->str();
    }
  }

  return "Miscellanous";
}

